def solve(n, q, a, queries):
    """
    Read input data, process queries, and compute the result for each query using the `f` function.
    """
    results = []
    for l, r in queries:
        subarray = a[l-1:r]  # Convert to 0-indexed
        result = f(subarray)
        results.append(result)
    return results

def f(arr):
    """
    Compute the final element of an array after repeatedly applying operations to delete 
    non-local minima and non-local maxima until only one element remains.
    """
    arr = list(arr)
    while len(arr) > 1:
        # Type 1: keep local minima
        arr = keep_local_minima(arr)
        if len(arr) <= 1:
            break
        # Type 2: keep local maxima
        arr = keep_local_maxima(arr)
        if len(arr) <= 1:
            break
    return arr[0]

def apply_operation(arr, op_type):
    """
    Apply a specific operation (either deleting non-local minima or non-local maxima) to an array.
    op_type: 1 for keeping local minima, 2 for keeping local maxima
    """
    if op_type == 1:
        return keep_local_minima(arr)
    else:
        return keep_local_maxima(arr)

def keep_local_minima(arr):
    """Keep only local minima from the array."""
    n = len(arr)
    if n == 1:
        return arr

    result = []
    for i in range(n):
        if is_local_min(arr, i):
            result.append(arr[i])
    return result

def keep_local_maxima(arr):
    """Keep only local maxima from the array."""
    n = len(arr)
    if n == 1:
        return arr

    result = []
    for i in range(n):
        if is_local_max(arr, i):
            result.append(arr[i])
    return result

def is_local_min(arr, i):
    """
    Determine if an element at index i in array arr is a local minimum.
    A local minimum is smaller than its immediate neighbors.
    """
    n = len(arr)
    if n == 1:
        return True
    if i == 0:
        return arr[i] < arr[i + 1]
    if i == n - 1:
        return arr[i] < arr[i - 1]
    return arr[i] < arr[i - 1] and arr[i] < arr[i + 1]

def is_local_max(arr, i):
    """
    Determine if an element at index i in array arr is a local maximum.
    A local maximum is larger than its immediate neighbors.
    """
    n = len(arr)
    if n == 1:
        return True
    if i == 0:
        return arr[i] > arr[i + 1]
    if i == n - 1:
        return arr[i] > arr[i - 1]
    return arr[i] > arr[i - 1] and arr[i] > arr[i + 1]
